import { pipe } from "fp-ts/function";
import * as O from "fp-ts/Option";

interface Person { readonly name: string; readonly age: number }

const asRecord = (u: unknown): O.Option<Record<string, unknown>> =>
  u !== null && typeof u === "object" ? O.some(u as Record<string, unknown>) : O.none;

const asString = (u: unknown): O.Option<string> =>
  typeof u === "string" ? O.some(u) : O.none;

const asNumber = (u: unknown): O.Option<number> =>
  typeof u === "number" && Number.isFinite(u) ? O.some(u) : O.none;

export const parsePerson = (u: unknown): O.Option<Person> =>
  pipe(
    u,
    O.fromNullable,
    O.chain(asRecord),
    O.chain((r) =>
      pipe(
        asString(r.name),
        O.chain((name) => pipe(asNumber(r.age), O.chain((age) => O.some({ name, age })))),
      ),
    ),
  );
```

