import { pipe } from "fp-ts/function";
import * as E from "fp-ts/Either";

interface Req { readonly url: string; readonly method: string }

const getField = (key: string) => (u: unknown): E.Either<string, unknown> =>
  u !== null && typeof u === "object" && key in u
    ? E.right((u as Record<string, unknown>)[key])
    : E.left(`missing:${key}`);

const asStr = (key: string) => (u: unknown): E.Either<string, string> =>
  typeof u === "string" ? E.right(u) : E.left(`not_string:${key}`);

export const parseReq = (u: unknown): E.Either<string, Req> =>
  pipe(
    E.Do,
    E.bind("url", () => pipe(getField("url")(u), E.chainW(asStr("url")))),
    E.bind("method", () => pipe(getField("method")(u), E.chainW(asStr("method")))),
  );
```

Option just says "yes/no" — the failure case is `O.none` with no explanation, which is fine when you only need a fallback. Either carries a typed error value, so callers can log, display, or branch on the reason. The rule I use: reach for Option when the only reasonable response is "skip this record"; reach for Either the moment you need to tell a user (or a log line) *why* a value was rejected.

