import { Data, Match } from "effect";

type ApiResult = Data.TaggedEnum<{
  Success: { readonly body: string };
  NotFound: { readonly path: string };
  ServerError: { readonly code: number };
}>;

const { Success, NotFound, ServerError, $match } = Data.taggedEnum<ApiResult>();

export { Success, NotFound, ServerError };

export const toMessage: (r: ApiResult) => string = $match({
  Success: (r) => `ok: ${r.body}`,
  NotFound: (r) => `404: ${r.path}`,
  ServerError: (r) => `500 code=${r.code}`,
});

// Alternative: Match module with exhaustive finaliser.
export const toStatus = (r: ApiResult): number =>
  Match.value(r).pipe(
    Match.tag("Success", () => 200),
    Match.tag("NotFound", () => 404),
    Match.tag("ServerError", (s) => s.code),
    Match.exhaustive,
  );
```

```typescript
import { Data, Match } from "effect";

type RemoteData<A, E> = Data.TaggedEnum<{
  Idle: {};
  Loading: {};
  Loaded: { readonly value: A };
  Failed: { readonly error: E };
}>;

interface RemoteDataDef extends Data.TaggedEnum.WithGenerics<2> {
  readonly taggedEnum: RemoteData<this["A"], this["B"]>;
}

const { Idle, Loading, Loaded, Failed } = Data.taggedEnum<RemoteDataDef>();
export { Idle, Loading, Loaded, Failed };

export const describe = (rd: RemoteData<string, string>): string =>
  Match.value(rd).pipe(
    Match.tag("Idle", () => "idle"),
    Match.tag("Loading", () => "loading"),
    Match.tag("Loaded", (r) => `loaded:${r.value}`),
    Match.tag("Failed", (r) => `failed:${r.error}`),
    Match.exhaustive,
  );
```

A manual `switch` on `_tag` compiles even when you forget a case — you just silently fall through the default branch. `Match.exhaustive` is a type-level finaliser that forces every tag to have been handled; adding a new variant to the union makes the match stop compiling until you handle it. Combined with `Data.taggedEnum`, the union and its constructors live in one declaration, so there's no drift between the type and the runtime values.

```typescript
