export const balanceDelta = (ev: PaymentEvent): number =>
  Match.value(ev).pipe(
    Match.tag("Authorised", () => 0),
    Match.tag("Captured", (c) => c.amount),
    Match.tag("Refunded", (r) => -r.amount),
