import { Data, Match } from "effect";

type FormState = Data.TaggedEnum<{
  Pristine: {};
  Editing: { readonly draft: string };
  Submitting: { readonly draft: string };
  Submitted: { readonly id: string };
}>;

const { Pristine, Editing, Submitting, Submitted } = Data.taggedEnum<FormState>();
export { Pristine, Editing, Submitting, Submitted };

type Action =
  | { readonly _tag: "Edit"; readonly draft: string }
  | { readonly _tag: "Submit" }
  | { readonly _tag: "Ack"; readonly id: string };

export const reduce = (s: FormState, a: Action): FormState =>
  Match.value(s).pipe(
    Match.tag("Pristine", () => (a._tag === "Edit" ? Editing({ draft: a.draft }) : s)),
    Match.tag("Editing", (e) =>
      a._tag === "Submit" ? Submitting({ draft: e.draft }) : e,
    ),
    Match.tag("Submitting", (s2) =>
      a._tag === "Ack" ? Submitted({ id: a.id }) : s2,
    ),
    Match.tag("Submitted", (x) => x),
    Match.exhaustive,
  );
