import { Config, Effect, pipe } from "effect";

interface ServerCfg { readonly host: string; readonly port: number }
interface LoggingCfg { readonly level: string }
interface AppCfg { readonly server: ServerCfg; readonly logging: LoggingCfg }

const serverCfg: Config.Config<ServerCfg> = Config.all({
  host: Config.string("HOST"),
  port: Config.integer("PORT"),
}).pipe(Config.nested("server"));

const loggingCfg: Config.Config<LoggingCfg> = Config.all({
  level: Config.string("LEVEL").pipe(Config.withDefault("info")),
}).pipe(Config.nested("logging"));

const appCfg: Config.Config<AppCfg> = Config.all({
  server: serverCfg,
  logging: loggingCfg,
});

export const loadCfg: Effect.Effect<AppCfg, never, never> = pipe(
  appCfg,
  Effect.orDie,
);
```

Reading `process.env.FOO` gives you `string | undefined`, and every consumer re-implements the parse/default/validation dance. `Config` describes the shape once — typed, with defaults and per-field errors — and since `Config<A>` already extends `Effect<A, ConfigError>` you can compose it with the rest of your program directly. Missing keys fail fast with a structured error instead of `undefined` propagating silently, and tests can swap the provider without monkey-patching `process.env`.

