import { pipe } from "fp-ts/function";
import * as A from "fp-ts/ReadonlyArray";
import * as N from "fp-ts/number";
import * as Ord from "fp-ts/Ord";
import * as S from "fp-ts/string";

type Role = "admin" | "editor" | "viewer";
interface User { readonly name: string; readonly role: Role }

const rank: Record<Role, number> = { admin: 0, editor: 1, viewer: 2 };

const byRole: Ord.Ord<User> = pipe(
  N.Ord,
  Ord.contramap((u: User) => rank[u.role]),
);

const byName: Ord.Ord<User> = pipe(
  S.Ord,
  Ord.contramap((u: User) => u.name),
);

export const sortUsers = (xs: ReadonlyArray<User>): ReadonlyArray<User> =>
  pipe(xs, A.sortBy([byRole, byName]));
```

```typescript
import { pipe } from "fp-ts/function";
import * as A from "fp-ts/ReadonlyArray";
import * as Eq from "fp-ts/Eq";
import * as S from "fp-ts/string";

interface Product { readonly sku: string; readonly price: number }

const eqBySku: Eq.Eq<Product> = pipe(
  S.Eq,
  Eq.contramap((p: Product) => p.sku),
);

export const uniqueBySku = (xs: ReadonlyArray<Product>): ReadonlyArray<Product> =>
  A.uniq(eqBySku)(xs);
```

`Ord<A>` knows how to compare values of type `A`. `Ord.contramap` takes a function `B -> A` and turns an `Ord<A>` into an `Ord<B>`. That's the exact shape you want for "I have a domain object, and I want to sort it by one of its fields" — point at the field, reuse the primitive `Ord` for its type, done. No hand-rolled compare function, no bugs from mis-ordering -1/0/1.

