import { pipe } from "fp-ts/function";
import * as A from "fp-ts/ReadonlyArray";
import * as N from "fp-ts/number";
import * as Ord from "fp-ts/Ord";
import { concatAll } from "fp-ts/Monoid";
import { getMonoid } from "fp-ts/Ord";

type Status = "overdue" | "open" | "paid";
interface Invoice { readonly id: string; readonly status: Status; readonly amount: number }

const rank: Record<Status, number> = { overdue: 0, open: 1, paid: 2 };

const byStatus: Ord.Ord<Invoice> = pipe(
  N.Ord,
  Ord.contramap((i: Invoice) => rank[i.status]),
);

const byAmountDesc: Ord.Ord<Invoice> = Ord.reverse(
  pipe(N.Ord, Ord.contramap((i: Invoice) => i.amount)),
);

export const ordInvoice: Ord.Ord<Invoice> = concatAll(getMonoid<Invoice>())([
  byStatus,
  byAmountDesc,
]);

export const sortInvoices = (xs: ReadonlyArray<Invoice>): ReadonlyArray<Invoice> =>
  pipe(xs, A.sort(ordInvoice));
