import { Data, Equal, Hash, pipe } from "effect";

interface Coord { readonly lat: number; readonly lon: number }

export const origin: Coord = Data.struct({ lat: 0, lon: 0 });
export const sameOrigin: Coord = Data.struct({ lat: 0, lon: 0 });
export const elsewhere: Coord = Data.struct({ lat: 1, lon: 1 });

export const equal: boolean = pipe(origin, Equal.equals(sameOrigin));
export const sameHash: boolean = Hash.hash(origin) === Hash.hash(sameOrigin);
export const differentHash: boolean = Hash.hash(origin) !== Hash.hash(elsewhere);
```

`Equal.equals` on `Data.struct` values is a two-step protocol — `Hash.hash` first, then structural compare only when hashes match — and both are computed once, then cached on the value. That's O(1) amortised lookup inside `HashSet` / `HashMap`, whereas a `deepEqual` library walks every field on every comparison. The Data wrapper also normalises object identity: two `Data.struct({x:1})` values hash and compare equal regardless of allocation order.

```typescript
import { Data, HashSet, pipe } from "effect";

interface Id { readonly tenant: string; readonly sku: string }

const mk = (tenant: string, sku: string): Id => Data.struct({ tenant, sku });

const seen: HashSet.HashSet<Id> = HashSet.make(
  mk("acme", "001"),
  mk("acme", "002"),
);

export const hasAcme001: boolean = pipe(seen, HashSet.has(mk("acme", "001")));
export const hasOther: boolean = pipe(seen, HashSet.has(mk("other", "001")));
```

```typescript
import { Data, Equal, Hash, pipe } from "effect";

export interface Money {
  readonly amount: number;
  readonly currency: string;
}

export const money = (amount: number, currency: string): Money =>
  Data.struct({ amount, currency });

export const equal = (a: Money, b: Money): boolean =>
  pipe(a, Equal.equals(b));

export const hash = (m: Money): number => Hash.hash(m);

// Demonstration.
export const usd5a: Money = money(5, "USD");
export const usd5b: Money = money(5, "USD");
export const eur5: Money = money(5, "EUR");

export const check1: boolean = equal(usd5a, usd5b); // true
export const check2: boolean = equal(usd5a, eur5); // false
```

```typescript
import { Data, Equal, pipe } from "effect";

const plainA: ReadonlyArray<number> = [1, 2, 3];
const plainB: ReadonlyArray<number> = [1, 2, 3];

// Plain arrays: reference equality only.
export const plainEqual: boolean = Equal.equals(plainA, plainB); // false

const dataA = Data.array([1, 2, 3]);
const dataB = Data.array([1, 2, 3]);

// Data arrays: structural equality.
export const dataEqual: boolean = pipe(dataA, Equal.equals(dataB)); // true

const nestedA = Data.array([Data.struct({ k: "a" }), Data.struct({ k: "b" })]);
const nestedB = Data.array([Data.struct({ k: "a" }), Data.struct({ k: "b" })]);

export const nestedEqual: boolean = Equal.equals(nestedA, nestedB); // true
```
